impl.spec_text:
trait T { spec fn f(&self) -> int; }
struct S {}
impl T for S { spec fn f(&self) -> int { 1 } }
impl T for int { spec fn f(&self) -> int { 2 + *self } }
impl T for spec_fn(int) -> int { spec fn f(&self) -> int { (*self)(3) } }

proof fn test(x: int, y: spec_fn(int) -> int) {
    assert(x.f() == x + 2);
    assert(y.f() == y(3));
}

